"""Eingebettetes App-Logo.

Das Logo liegt als base64-PNG direkt im Code, damit App und Paketbau keine
externe Bilddatei brauchen (frischer Clone baut ohne Zusatzschritt).
logo_texture() liefert es fuer die Oberflaeche, logo_bytes() die rohen PNG-Bytes
fuer die Icon-Skalierung im Build.
"""

import base64

_PNG_B64 = ""  # noqa: E501


def logo_bytes():
    """Rohe PNG-Bytes des eingebetteten Logos. Bewusst ohne GTK-Import, damit
    der Build die Icons daraus ableiten kann, ohne PyGObject zu laden."""
    return base64.b64decode(_PNG_B64)


def logo_texture():
    """Gdk.Texture des Logos, ohne externe Datei. Pixbuf-Weg fuer breite
    GTK-Kompatibilitaet (ab 4.0)."""
    from gi.repository import Gdk, GdkPixbuf, Gio, GLib
    stream = Gio.MemoryInputStream.new_from_bytes(GLib.Bytes.new(logo_bytes()))
    pixbuf = GdkPixbuf.Pixbuf.new_from_stream(stream, None)
    return Gdk.Texture.new_for_pixbuf(pixbuf)
